import { describe, expect, it } from 'vitest';

import {
  UNLIMITED_OCR_ARTIFACTS,
  UNLIMITED_OCR_CHAT_TEMPLATE,
  UNLIMITED_OCR_DEFAULT_PROMPT,
  UNLIMITED_OCR_MMPROJ_FILENAME,
  UNLIMITED_OCR_MODEL_FILENAME,
  UNLIMITED_OCR_QSPEC_MAX_TOKENS,
  UNLIMITED_OCR_REPO_ID,
  buildUnlimitedOcrChatRequest,
  validateUnlimitedOcrOutput,
  type UnlimitedOcrProbeSpec,
} from '../unlimited-ocr-qspec';

describe('Unlimited OCR qspec support', () => {
  const spec: UnlimitedOcrProbeSpec = {
    probe: 'unlimited-ocr-gguf',
    model: 'unlimited-ocr',
    modality: 'ocr',
    gate_tier: 'visible-document-ocr',
    artifacts: UNLIMITED_OCR_ARTIFACTS,
    prompt: UNLIMITED_OCR_DEFAULT_PROMPT,
    input: {
      pdf: '/Users/buley/Downloads/A Eulogy for Dark Sky, a Data Visualization Masterpiece.pdf',
      renderPage: 1,
      renderDpi: 180,
    },
    decode: {
      maxTokens: UNLIMITED_OCR_QSPEC_MAX_TOKENS,
      ignoreEos: true,
    },
    expect: {
      minTextChars: 80,
      requiredTerms: ['Dark Sky', 'data visualization'],
    },
  };

  it('pins the GGUF decoder and projector artifacts', () => {
    expect(spec.artifacts).toEqual({
      repoId: UNLIMITED_OCR_REPO_ID,
      quant: 'Q4_K_M',
      modelFilename: UNLIMITED_OCR_MODEL_FILENAME,
      mmprojFilename: UNLIMITED_OCR_MMPROJ_FILENAME,
      chatTemplate: UNLIMITED_OCR_CHAT_TEMPLATE,
    });
  });

  it('builds the OpenAI-compatible multimodal request used by CF mesh routes', () => {
    const request = buildUnlimitedOcrChatRequest({
      imageUrl: 'data:image/png;base64,abc123',
    });

    expect(request.model).toBe('unlimited-ocr');
    expect(request.temperature).toBe(0);
    expect(request.messages).toEqual([
      {
        role: 'user',
        content: [
          { type: 'text', text: UNLIMITED_OCR_DEFAULT_PROMPT },
          {
            type: 'image_url',
            image_url: { url: 'data:image/png;base64,abc123' },
          },
        ],
      },
    ]);
  });

  it('passes the Dark Sky PDF proof terms and rejects missing OCR text', () => {
    expect(
      validateUnlimitedOcrOutput(
        'A Eulogy for Dark Sky, a Data Visualization Masterpiece. Dark Sky changed weather maps.',
        spec
      )
    ).toEqual({ pass: true });

    expect(validateUnlimitedOcrOutput('short unrelated text', spec)).toEqual({
      pass: false,
      missingTerms: ['Dark Sky', 'data visualization'],
      textChars: 20,
    });
  });
});
